detailRead.query:
#graphql
  #graphql
  fragment FulfillmentEventCreateValidationFulfillmentFields on Fulfillment {
    id
    status
    displayStatus
    estimatedDeliveryAt
    inTransitAt
    events(first: 5) {
      nodes {
        id
        status
        message
        happenedAt
        createdAt
        estimatedDeliveryAt
        city
        province
        country
        zip
        address1
        latitude
        longitude
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
        startCursor
        endCursor
      }
    }
  }

  query FulfillmentEventCreateValidationDetailRead($fulfillmentId: ID!) {
    fulfillment(id: $fulfillmentId) {
      ...FulfillmentEventCreateValidationFulfillmentFields
    }
  }

